
.stat-block {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.stat-row {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  gap: 6px;
  padding: 4px 6px;
  border-radius: var(--radius-xs);
  font-size: 0.78rem;
  line-height: 1.5;
  transition: background var(--transition-fast);
  min-width: 0;
  max-width: 100%;

  &:hover {
    background: rgba(176, 125, 68, 0.04);
  }
}

.stat-label {
  font-weight: 600;
  color: var(--text-primary);
  white-space: nowrap;
  flex-shrink: 0;
  font-size: 0.75rem;

  &::after {
    content: ':';
  }
}

.stat-value {
  color: var(--text-secondary);
  word-break: break-word;
  overflow-wrap: anywhere;
  font-size: 0.72rem;
  min-width: 0;
  flex: 1 1 auto;

  &.pre {
    white-space: pre-line;
    font-size: 0.78rem;
  }
}

@media (max-width: 640px) {
  .stat-label {
    white-space: normal;
    max-width: 40%;
    overflow-wrap: anywhere;
  }

  .stat-value {
    flex: 1 1 55%;
  }
}
