
.ledger {
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
}

.ledger-global-header {
  display: flex;
  flex-direction: row;
  align-items: stretch;
  gap: 8px;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
  padding: 6px 8px 6px 10px;
  min-height: 0;
  line-height: 1.25;
  background: var(--bg-card);
  border: 1px solid var(--border-card);
  border-radius: var(--radius-sm);
  cursor: pointer;
  user-select: none;
  box-shadow: var(--shadow-xs);
  transition: box-shadow var(--transition-smooth), border-color var(--transition-fast);
  position: sticky;
  top: 2px;
  z-index: 20;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  margin: 0;
  -webkit-tap-highlight-color: transparent;
  overflow: hidden;

  &:hover {
    box-shadow: var(--shadow-sm), var(--shadow-glow);
    border-color: var(--border-accent);
  }
}

.gh-body {
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 3px;
  flex: 1 1 auto;
  min-width: 0;
}

.gh-row {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
  width: 100%;
}

.gh-row--title {
  flex-wrap: nowrap;
  gap: 5px;
  overflow: hidden;
}

.gh-actions {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
}

.gh-actions--stack {
  flex-direction: column;
  justify-content: center;
  gap: 4px;
  align-self: center;
}

.gh-row--meta {
  flex-wrap: nowrap;
  align-items: center;
  justify-content: space-between;
  gap: 6px;
  overflow: hidden;
}

.gh-meta-group {
  display: flex;
  align-items: center;
  flex-wrap: nowrap;
  gap: 4px;
  min-width: 0;
}

.gh-meta-group--left {
  flex-shrink: 0;
}

.gh-meta-group--right {
  margin-left: auto;
  flex-shrink: 1;
  justify-content: flex-end;
  min-width: 0;
}

.gh-icon {
  font-size: 1.05rem;
  flex-shrink: 0;
  line-height: 1;
}

.gh-main-title {
  font-family: var(--font-display);
  font-size: 0.92rem;
  font-weight: 700;
  letter-spacing: 0.3px;
  color: var(--text-primary);
  line-height: 1.2;
  white-space: nowrap;
  flex-shrink: 0;
}

.gh-subtitle {
  margin: 0;
  padding: 0;
  font-size: 0.68rem;
  font-weight: 500;
  color: var(--text-tertiary);
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
  flex: 1 1 auto;
}

.gh-pill {
  font-size: 0.65rem;
  font-weight: 600;
  padding: 1px 7px;
  border-radius: 10px;
  background: rgba(176, 125, 68, 0.12);
  color: var(--accent-primary);
  border: 1px solid var(--border-accent);
  white-space: nowrap;
  flex-shrink: 0;
  line-height: 1.4;
}

.gh-delta {
  font-family: var(--font-mono);
  font-size: 0.72rem;
  font-weight: 700;
  color: var(--accent-green);
  white-space: nowrap;
  flex-shrink: 0;
}

.gh-cash {
  font-family: var(--font-mono);
  font-size: 0.72rem;
  font-weight: 700;
  color: var(--accent-teal, var(--accent-primary));
  white-space: nowrap;
  flex-shrink: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.gh-arrow {
  font-size: 10px;
  color: var(--accent-primary);
  width: 22px;
  height: 22px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  background: rgba(176, 125, 68, 0.1);
  transition: transform 0.35s cubic-bezier(0.33, 1, 0.68, 1);
  flex-shrink: 0;
  line-height: 1;

  &.open {
    transform: rotate(180deg);
  }
}

.gh-theme-btn {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--border-subtle);
  color: var(--text-secondary);
  font-size: 13px;
  cursor: pointer;
  width: 24px;
  height: 24px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--transition-fast);
  flex-shrink: 0;
  padding: 0;
  line-height: 1;

  &:hover {
    background: rgba(176, 125, 68, 0.15);
    border-color: var(--border-accent);
    color: var(--accent-primary);
  }
}

.ledger-body {
  padding: 10px 0 0;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.ledger-toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.tb-btn {
  font: inherit;
  font-size: 0.75rem;
  padding: 0.3em 0.75em;
  border: 1px solid var(--border-card);
  border-radius: var(--radius-xs);
  background: var(--bg-card);
  color: var(--text-secondary);
  cursor: pointer;
  box-shadow: var(--shadow-xs);

  &:hover {
    border-color: var(--border-accent);
    color: var(--accent-primary);
  }
}

.highlight-block {
  background: linear-gradient(135deg, rgba(176, 125, 68, 0.08) 0%, rgba(176, 125, 68, 0.02) 100%);
  border: 1px solid var(--border-accent);
  border-radius: var(--radius-sm);
  padding: 10px 12px;
  margin: 8px 0;
}

.hl-label {
  font-size: 0.72rem;
  font-weight: 700;
  color: var(--text-primary);
  margin-bottom: 4px;
}

.factor-row {
  margin: 8px 0;
  padding: 6px 0;
  border-bottom: 1px dashed var(--border-subtle);

  &:last-child {
    border-bottom: 0;
  }
}

.factor-head {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: 4px 8px;
  margin-bottom: 2px;
}

.factor-title {
  font-size: 0.85rem;
  font-weight: 650;
  color: var(--text-primary);
}

.factor-summary {
  flex: 1 1 8em;
  min-width: 0;
  font-size: 0.68rem;
  color: var(--text-tertiary);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.item-row {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: 4px 8px;
  padding: 6px 4px;
  border-bottom: 1px dashed var(--border-subtle);
  font-size: 0.82rem;
  overflow-wrap: anywhere;
}

.muted {
  color: var(--text-tertiary);
  font-size: 0.85em;
}

.staff-note {
  margin: 0 0 0.4em;
}

.tag {
  display: inline-block;
  font-size: 0.65rem;
  font-weight: 600;
  padding: 2px 7px;
  border-radius: 8px;
  letter-spacing: 0.3px;
}

.tag-primary {
  background: rgba(176, 125, 68, 0.15);
  color: var(--accent-primary);
  border: 1px solid rgba(176, 125, 68, 0.25);
}

.tag-warm {
  background: rgba(184, 92, 56, 0.15);
  color: var(--accent-warm);
  border: 1px solid rgba(184, 92, 56, 0.25);
}

.tag-green {
  background: rgba(74, 124, 92, 0.15);
  color: var(--accent-green);
  border: 1px solid rgba(74, 124, 92, 0.25);
}

.tag-red {
  background: rgba(184, 72, 58, 0.15);
  color: var(--accent-red);
  border: 1px solid rgba(184, 72, 58, 0.25);
}

.stat-inline {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: 6px;
  font-size: 0.82rem;
  color: var(--text-primary);
}

.stat-inline__icon {
  opacity: 0.85;
}

.footer-note {
  text-align: center;
  font-size: 0.62rem;
  color: var(--text-muted);
  padding: 8px 0 4px;
  letter-spacing: 1px;
  border-top: 1px solid var(--border-subtle);
}

@media (max-width: 640px) {
  .ledger-global-header {
    padding: 6px 8px 6px 10px;
    gap: 6px;
  }

  .gh-body {
    gap: 2px;
  }

  .gh-main-title {
    font-size: 0.84rem;
  }

  .gh-subtitle {
    font-size: 0.6rem;
  }

  .gh-row--meta {
    gap: 3px 5px;
  }

  .gh-pill {
    font-size: 0.58rem;
    padding: 1px 5px;
  }

  .gh-delta,
  .gh-cash {
    font-size: 0.6rem;
  }

  .gh-theme-btn {
    width: 28px;
    height: 28px;
    font-size: 13px;
  }

  .gh-arrow {
    width: 28px;
    height: 28px;
    font-size: 11px;
  }

  .ledger-body {
    padding-top: 8px;
    gap: 10px;
  }

  .tb-btn {
    font-size: 0.72rem;
    padding: 0.45em 1em;
    min-height: 36px;
  }

  .highlight-block {
    padding: 8px 10px;
    margin: 6px 0;
  }

  .factor-summary {
    flex-basis: 100%;
    white-space: normal;
    overflow: visible;
    text-overflow: unset;
    overflow-wrap: anywhere;
  }
}
