
.attrs {
  display: flex;
  flex-wrap: wrap;
  gap: 0.25em 0.65em;
  margin-bottom: 0.25em;
  max-width: 100%;
  min-width: 0;
}

.attrs__item {
  font-size: 0.72rem;
  color: var(--text-secondary);
  max-width: 100%;
  overflow-wrap: anywhere;
}

.attrs__k {
  opacity: 0.7;
  &::after {
    content: ':';
    margin-right: 0.2em;
  }
}

.attrs__v {
  font-weight: 550;
  overflow-wrap: anywhere;
}
